mapper.select:
SELECT id, name, slug, usage_count AS usageCount FROM wallpaper_tag WHERE enabled = 1
AND (name LIKE CONCAT('%', #{keyword}, '%') OR slug LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY usage_count DESC, id ASC LIMIT #{limit}

SELECT id, name, slug, creator_username AS creatorUsername, enabled, usage_count AS usageCount, created_at AS createdAt, updated_at AS updatedAt FROM wallpaper_tag
AND (name LIKE CONCAT('%', #{keyword}, '%') OR slug LIKE CONCAT('%', #{keyword}, '%'))
AND enabled = #{enabled}
ORDER BY usage_count DESC, id DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM wallpaper_tag
AND (name LIKE CONCAT('%', #{keyword}, '%') OR slug LIKE CONCAT('%', #{keyword}, '%'))
AND enabled = #{enabled}

mapper.update:
UPDATE wallpaper_tag
SET name = #{name},
    slug = #{slug},
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE wallpaper_tag
SET enabled = #{enabled},
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE wallpaper_tag
SET usage_count = (
    SELECT COUNT(*) FROM wallpaper_tag_ref WHERE tag_id = #{id}
)
WHERE id = #{id}
